// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/policy/api"
	"github.com/cilium/cilium/pkg/policy/types"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)
	assert.Equal(t, logrus.InfoLevel, logger.logLevel)
}

func TestLogDecision(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)

	// Test LogDecision with different verdicts
	testCases := []struct {
		name    string
		identity identity.NumericIdentity
		policy  string
		verdict api.Decision
		reason  string
	}{
		{
			name:     "allowed decision",
			identity: identity.NumericIdentity(100),
			policy:   "test-policy",
			verdict:  api.Allowed,
			reason:   "matched allow rule",
		},
		{
			name:     "denied decision",
			identity: identity.NumericIdentity(200),
			policy:   "deny-policy",
			verdict:  api.Denied,
			reason:   "matched deny rule",
		},
		{
			name:     "undecided verdict",
			identity: identity.NumericIdentity(300),
			policy:   "unclear-policy",
			verdict:  api.Undecided,
			reason:   "no matching rules",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Should not panic
			assert.NotPanics(t, func() {
				logger.LogDecision(tc.identity, tc.policy, tc.verdict, tc.reason)
			})
		})
	}
}

func TestLogEvaluation(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	ctx := context.Background()
	policyKey := types.Key{
		Identity:        100,
		DestPort:        80,
		Nexthdr:         6, // TCP
		TrafficDirection: 1, // Ingress
	}

	// Create a minimal SelectorCache for testing
	repo := NewPolicyRepository()
	require.NotNil(t, repo)

	selectorCache := repo.GetSelectorCache()
	require.NotNil(t, selectorCache)

	testCases := []struct {
		name   string
		result api.Decision
	}{
		{
			name:   "evaluation allowed",
			result: api.Allowed,
		},
		{
			name:   "evaluation denied",
			result: api.Denied,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Should not panic
			assert.NotPanics(t, func() {
				logger.LogEvaluation(ctx, policyKey, selectorCache, tc.result)
			})
		})
	}
}

func TestLogDecisionJSON(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	identity := identity.NumericIdentity(100)
	policy := "test-policy"
	verdict := api.Allowed
	reason := "matched allow rule"

	// Should not panic
	assert.NotPanics(t, func() {
		logger.LogDecisionJSON(identity, policy, verdict, reason)
	})
}

func TestLogEvaluationJSON(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	ctx := context.Background()
	policyKey := types.Key{
		Identity:        100,
		DestPort:        443,
		Nexthdr:         6,
		TrafficDirection: 0, // Egress
	}

	repo := NewPolicyRepository()
	require.NotNil(t, repo)

	selectorCache := repo.GetSelectorCache()
	require.NotNil(t, selectorCache)

	// Should not panic
	assert.NotPanics(t, func() {
		logger.LogEvaluationJSON(ctx, policyKey, selectorCache, api.Denied)
	})
}

func TestSetLogLevel(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	assert.Equal(t, logrus.InfoLevel, logger.logLevel)

	logger.SetLogLevel(logrus.DebugLevel)
	assert.Equal(t, logrus.DebugLevel, logger.logLevel)

	logger.SetLogLevel(logrus.WarnLevel)
	assert.Equal(t, logrus.WarnLevel, logger.logLevel)
}

func TestThreadSafety(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	ctx := context.Background()
	policyKey := types.Key{
		Identity:        100,
		DestPort:        80,
		Nexthdr:         6,
		TrafficDirection: 1,
	}

	repo := NewPolicyRepository()
	require.NotNil(t, repo)

	selectorCache := repo.GetSelectorCache()
	require.NotNil(t, selectorCache)

	// Simulate concurrent logging operations
	done := make(chan bool)

	// Run multiple goroutines that log simultaneously
	for i := 0; i < 10; i++ {
		go func(id int) {
			defer func() { done <- true }()

			currentIdentity := identity.NumericIdentity(100 + id)
			logger.LogDecision(currentIdentity, "test-policy", api.Allowed, "test reason")
			logger.LogEvaluation(ctx, policyKey, selectorCache, api.Allowed)
			logger.LogDecisionJSON(currentIdentity, "test-policy", api.Denied, "test reason")
			logger.SetLogLevel(logrus.DebugLevel)
		}(i)
	}

	// Wait for all goroutines to finish
	for i := 0; i < 10; i++ {
		<-done
	}
}

func TestJSONAuditEntry(t *testing.T) {
	entry := JSONAuditEntry{
		Type:    "policy_decision",
		Identity: 100,
		Policy:  "test-policy",
		Verdict: "allowed",
		Reason:  "test reason",
	}

	// Test that the entry can be marshaled to JSON
	data, err := json.Marshal(entry)
	require.NoError(t, err)
	assert.NotEmpty(t, data)

	// Test that the JSON can be unmarshaled
	var unmarshaled JSONAuditEntry
	err = json.Unmarshal(data, &unmarshaled)
	require.NoError(t, err)
	assert.Equal(t, entry.Type, unmarshaled.Type)
	assert.Equal(t, entry.Identity, unmarshaled.Identity)
	assert.Equal(t, entry.Policy, unmarshaled.Policy)
}

