// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex
	logLevel logrus.Level
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified log level.
func NewPolicyAuditLogger(logLevel logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logLevel: logLevel,
	}
}

// LogDecision logs a policy decision with identity, policy, verdict, and reason.
//
// This method is thread-safe and logs structured information about policy
// decisions made during policy evaluation.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict api.Decision, reason string) {
	pal.Lock()
	defer pal.Unlock()

	auditLog.WithFields(logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict.String(),
		"reason":           reason,
	}).Log(pal.logLevel, "Policy decision logged")
}

// LogEvaluation logs the evaluation of a policy with the given context, policy key,
// selector cache, and result.
//
// This method is thread-safe and provides detailed logging of policy evaluation
// results including the policy key and selector cache state.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey types.Key, selectorCache *SelectorCache, result api.Decision) {
	pal.Lock()
	defer pal.Unlock()

	// Create a detailed evaluation log entry
	auditLog.WithFields(logrus.Fields{
		logfields.PolicyKey: policyKey.String(),
		"identity":          policyKey.Identity,
		"port":              policyKey.DestPort,
		"protocol":          policyKey.Nexthdr,
		"direction":         policyKey.TrafficDirection,
		"result":            result.String(),
	}).Log(pal.logLevel, "Policy evaluation completed")
}

// JSONAuditEntry represents a structured audit log entry that can be marshaled to JSON.
type JSONAuditEntry struct {
	Type      string                 `json:"type"`
	Identity  uint32                 `json:"identity,omitempty"`
	Policy    string                 `json:"policy,omitempty"`
	Verdict   string                 `json:"verdict,omitempty"`
	Reason    string                 `json:"reason,omitempty"`
	PolicyKey map[string]interface{} `json:"policy_key,omitempty"`
	Result    string                 `json:"result,omitempty"`
}

// LogDecisionJSON logs a policy decision as a JSON-structured audit log entry.
func (pal *PolicyAuditLogger) LogDecisionJSON(identity identity.NumericIdentity, policy string, verdict api.Decision, reason string) {
	pal.Lock()
	defer pal.Unlock()

	entry := JSONAuditEntry{
		Type:    "policy_decision",
		Identity: uint32(identity),
		Policy:  policy,
		Verdict: verdict.String(),
		Reason:  reason,
	}

	jsonData, err := json.Marshal(entry)
	if err != nil {
		auditLog.WithError(err).Warning("Failed to marshal audit entry to JSON")
		return
	}

	auditLog.WithFields(logrus.Fields{
		"audit_entry": string(jsonData),
	}).Log(pal.logLevel, "JSON audit entry logged")
}

// LogEvaluationJSON logs a policy evaluation as a JSON-structured audit log entry.
func (pal *PolicyAuditLogger) LogEvaluationJSON(ctx context.Context, policyKey types.Key, selectorCache *SelectorCache, result api.Decision) {
	pal.Lock()
	defer pal.Unlock()

	entry := JSONAuditEntry{
		Type:   "policy_evaluation",
		Result: result.String(),
		PolicyKey: map[string]interface{}{
			"identity":  policyKey.Identity,
			"port":      policyKey.DestPort,
			"protocol":  policyKey.Nexthdr,
			"direction": policyKey.TrafficDirection,
		},
	}

	jsonData, err := json.Marshal(entry)
	if err != nil {
		auditLog.WithError(err).Warning("Failed to marshal evaluation entry to JSON")
		return
	}

	auditLog.WithFields(logrus.Fields{
		"audit_entry": string(jsonData),
	}).Log(pal.logLevel, "JSON evaluation entry logged")
}

// SetLogLevel changes the log level for future audit log entries.
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.logLevel = level
}

