func TestThreadSafety(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	ctx := context.Background()
	policyKey := types.Key{
		Identity:        100,
		DestPort:        80,
		Nexthdr:         6,
		TrafficDirection: 1,
	}

	repo := NewPolicyRepository()
	require.NotNil(t, repo)

	selectorCache := repo.GetSelectorCache()
	require.NotNil(t, selectorCache)

	// Simulate concurrent logging operations
	done := make(chan bool)

	// Run multiple goroutines that log simultaneously
	for i := 0; i < 10; i++ {
		go func(id int) {
			defer func() { done <- true }()

			currentIdentity := identity.NumericIdentity(100 + id)
			logger.LogDecision(currentIdentity, "test-policy", api.Allowed, "test reason")
			logger.LogEvaluation(ctx, policyKey, selectorCache, api.Allowed)
			logger.LogDecisionJSON(currentIdentity, "test-policy", api.Denied, "test reason")
			logger.SetLogLevel(logrus.DebugLevel)
		}(i)
	}

	// Wait for all goroutines to finish
	for i := 0; i < 10; i++ {
		<-done
	}
}

